// --- 3D DOOR LOGIC (Three.js + GSAP) ---
document.addEventListener('DOMContentLoaded', () => {
  const doorContainer = document.getElementById('webgl-door-container');
  if (doorContainer) {
    const scene = new THREE.Scene();
    const camera = new THREE.PerspectiveCamera(75, window.innerWidth / window.innerHeight, 0.1, 1000);
    const renderer = new THREE.WebGLRenderer({ alpha: true, antialias: true });

    const width = doorContainer.clientWidth || window.innerWidth;
    const height = doorContainer.clientHeight || window.innerHeight;

    renderer.setSize(width, height);
    renderer.setPixelRatio(Math.min(window.devicePixelRatio, 2));
    doorContainer.appendChild(renderer.domElement);

    // Load the iron gate texture
    const textureLoader = new THREE.TextureLoader();
    const doorTexture = textureLoader.load('data:image/png;base64,');

    const material = new THREE.MeshBasicMaterial({
      map: doorTexture,
      transparent: true,
      side: THREE.DoubleSide,
      depthWrite: false, // Ensures transparent parts don't clip each other
    });

    // Ensure the container is on top initially
    doorContainer.style.zIndex = "100";

    // LEFT DOOR HALF (Base 1x1 size to be scaled dynamically)
    const leftGeometry = new THREE.PlaneGeometry(1, 1);
    const uvsLeft = leftGeometry.attributes.uv.array;
    for (let i = 0; i < uvsLeft.length; i += 2) {
      uvsLeft[i] = uvsLeft[i] * 0.5;
    }
    const leftDoor = new THREE.Mesh(leftGeometry, material);
    const leftPivot = new THREE.Group();
    scene.add(leftPivot);
    leftPivot.add(leftDoor);

    // RIGHT DOOR HALF (Base 1x1 size to be scaled dynamically)
    const rightGeometry = new THREE.PlaneGeometry(1, 1);
    const uvsRight = rightGeometry.attributes.uv.array;
    for (let i = 0; i < uvsRight.length; i += 2) {
      uvsRight[i] = 0.5 + (uvsRight[i] * 0.5);
    }
    const rightDoor = new THREE.Mesh(rightGeometry, material);
    const rightPivot = new THREE.Group();
    scene.add(rightPivot);
    rightPivot.add(rightDoor);

    camera.position.z = 10;

    function resizeDoors() {
      const vFov = (camera.fov * Math.PI) / 180;
      const frustumHeight = 2 * Math.tan(vFov / 2) * camera.position.z;
      const frustumWidth = frustumHeight * camera.aspect;

      // To fit edge-to-edge, we force the doors to match the frustum exact dimensions.
      // This will stretch the image if the aspect ratio doesn't match, but it guarantees edge-to-edge.
      const planeWidth = frustumWidth;
      const planeHeight = frustumHeight;

      const halfWidth = planeWidth / 2;

      leftDoor.scale.set(halfWidth, planeHeight, 1);
      leftDoor.position.x = halfWidth / 2;
      leftPivot.position.x = -halfWidth;

      rightDoor.scale.set(halfWidth, planeHeight, 1);
      rightDoor.position.x = -halfWidth / 2;
      rightPivot.position.x = halfWidth;
    }

    resizeDoors();

    // GSAP Animation
    if (typeof gsap !== 'undefined' && typeof ScrollTrigger !== 'undefined') {
      gsap.registerPlugin(ScrollTrigger);

      const tl = gsap.timeline({
        scrollTrigger: {
          trigger: "#welcome-section",
          start: "top top",
          end: "+=1500", // Leaves time for doors to visibly open
          scrub: 1,
          pin: true, // Pin the section while the animation happens
          pinSpacing: true, // Forces the next sections down while pinned
          onUpdate: (self) => {
            const welcomeText = document.getElementById("welcome-text");
            if (welcomeText) {
              if (self.progress > 0.3) {
                welcomeText.classList.add("reveal-active");
              } else {
                welcomeText.classList.remove("reveal-active");
              }
            }
          }
        }
      });

      // Opening towards viewer: 
      // Left door swings inwards/towards: negative rotation Y
      // Right door swings inwards/towards: positive rotation Y
      // Also move camera forward slightly to enhance the 'passing through' effect.
      tl.to(".scroll-hint", { autoAlpha: 0, duration: 0.1 }, 0) // Instantly fade out hint
        .to(leftPivot.rotation, { y: Math.PI / 1.5, ease: "power1.inOut" }, 0)
        .to(rightPivot.rotation, { y: -Math.PI / 1.5, ease: "power1.inOut" }, 0)
        .to(camera.position, { z: 4, ease: "power1.inOut" }, 0)
        .to(doorContainer, { autoAlpha: 0, ease: "power1.inOut" }, 0.8);
    }

    // Pin the Gamer Girl Section so it acts as a distinct full-screen experience
    const sectionContainer = document.getElementById("gamer-girl-section");
    if (sectionContainer) {
      ScrollTrigger.create({
        trigger: sectionContainer,
        start: "top top",
        end: "+=1000", // Leaves time to appreciate the illustration
        pin: true,
        pinSpacing: true
      });
    }

    function animate() {
      requestAnimationFrame(animate);
      renderer.render(scene, camera);
    }
    animate();

    window.addEventListener('resize', () => {
      const newWidth = doorContainer.clientWidth || window.innerWidth;
      const newHeight = doorContainer.clientHeight || window.innerHeight;

      camera.aspect = newWidth / newHeight;
      camera.updateProjectionMatrix();
      renderer.setSize(newWidth, newHeight);
      resizeDoors();
    });
  }
});

// --- SPARSE STARS GENERATOR ---
document.addEventListener('DOMContentLoaded', () => {
  const containers = document.querySelectorAll('.stars-container');
  containers.forEach(container => {
    const isFirstPage = container.id === 'sparse-stars-container';
    const starCount = isFirstPage ? 80 : 40; // More stars on the first page!

    for (let i = 0; i < starCount; i++) {
      const star = document.createElement('div');
      star.classList.add('sparse-star');
      // Random position
      star.style.top = `${Math.random() * 100}%`;
      star.style.left = `${Math.random() * 100}%`;
      // Random size
      const size = Math.random() * 2 + 1; // 1px to 3px
      star.style.width = `${size}px`;
      star.style.height = `${size}px`;

      // If we're on the first page, make some of them randomly colored!
      if (isFirstPage && Math.random() > 0.5) { // 50% chance to be colored
        const colors = [
          'rgba(255, 150, 150, 0.9)', // Red/Pink
          'rgba(150, 255, 150, 0.9)', // Green
          'rgba(150, 150, 255, 0.9)', // Blue
          'rgba(255, 255, 150, 0.9)', // Yellow
          'rgba(202, 164, 103, 0.9)'  // Gold
        ];
        star.style.backgroundColor = colors[Math.floor(Math.random() * colors.length)];
      }

      // Random animation delay and duration to make them twinkle asynchronously
      star.style.animationDelay = `${Math.random() * 5}s`;
      star.style.animationDuration = `${Math.random() * 3 + 2}s`;

      container.appendChild(star);
    }
  });
});

// State
const cat = document.getElementById('cat');

// Audio setup
let audioStarted = false;
document.addEventListener('click', () => {
  if (!audioStarted) {
    const bgm = document.getElementById('bgm');
    if (bgm && bgm.paused) {
      bgm.volume = 0.3;
      bgm.play().catch(e => console.log("Audio play blocked by browser:", e));
      audioStarted = true;
    }
  }
});

// Cat logic
function setCatPose(pose) {
  cat.classList.remove('pose-sit', 'pose-walk', 'pose-point');
  cat.classList.add(`pose-${pose}`);
}

function triggerCatWalk() {
  if (cat.classList.contains('pose-walk')) return;

  setCatPose('walk');

  // Pick new X in [-100, 100] relative to right corner
  let newX = Math.random() * 200 - 100;

  const currentX = parseFloat(cat.dataset.x) || 0;
  const direction = newX > currentX ? -1 : 1;

  cat.style.transform = `translateX(${newX}px) scaleX(${direction})`;
  cat.dataset.x = newX;

  setTimeout(() => {
    // Randomly pick next resting pose
    setCatPose(Math.random() > 0.5 ? 'sit' : 'point');
  }, 1000);
}

// Observe scrolling sections to trigger cat movement
const observer = new IntersectionObserver((entries) => {
  entries.forEach(entry => {
    if (entry.isIntersecting) {
      if ((entry.target.id === 'hero' || entry.target.id === 'gate-cover') && window.scrollY < 100) {
        cat.classList.add('hidden');
      } else {
        cat.classList.remove('hidden');
        triggerCatWalk();
      }
    }
  });
}, { threshold: 0.5 });

document.querySelectorAll('.scroll-section').forEach(section => {
  observer.observe(section);
});

