// --- GAME GALLERY MODAL LOGIC ---
const galleryItems = document.querySelectorAll('.gallery-item');
const gameModal = document.getElementById('game-modal');
const modalClose = document.querySelector('.modal-close');
const modalVideo = document.getElementById('modal-video');
const modalTitle = document.getElementById('modal-title');
const modalHeading = document.getElementById('modal-heading');
const modalDesc = document.getElementById('modal-desc');
const modalCaption = document.getElementById('modal-caption');
const modalLinks = document.getElementById('modal-links');

function resetModal() {
  modalVideo.pause();
  modalVideo.removeAttribute('src');
  modalVideo.style.display = 'none';
  modalTitle.textContent = '';
  modalHeading.style.display = 'none';
  modalHeading.textContent = '';
  modalDesc.style.display = 'none';
  modalDesc.textContent = '';
  modalCaption.style.display = 'none';
  modalCaption.textContent = '';
  modalLinks.innerHTML = '';
}

function buildLinks(item) {
  const link1 = item.getAttribute('data-link1');
  const link1Label = item.getAttribute('data-link1-label') || 'Link 1';
  const link2 = item.getAttribute('data-link2');
  const link2Label = item.getAttribute('data-link2-label') || 'Link 2';
  if (link1) {
    const a = document.createElement('a');
    a.href = link1; a.target = '_blank'; a.rel = 'noopener noreferrer';
    a.textContent = link1Label;
    a.style.cssText = 'color:var(--accent-gold);text-decoration:underline;font-size:1rem;';
    modalLinks.appendChild(a);
  }
  if (link2) {
    const a = document.createElement('a');
    a.href = link2; a.target = '_blank'; a.rel = 'noopener noreferrer';
    a.textContent = link2Label;
    a.style.cssText = 'color:var(--accent-gold);text-decoration:underline;font-size:1rem;';
    modalLinks.appendChild(a);
  }
}

if (galleryItems.length && gameModal) {
  galleryItems.forEach(item => {
    item.addEventListener('click', () => {
      resetModal();
      const title = item.getAttribute('data-title');
      const type = item.getAttribute('data-type');
      modalTitle.textContent = title;

      if (type === 'video') {
        const videoSrc = item.getAttribute('data-video');
        modalVideo.src = videoSrc;
        modalVideo.style.display = 'block';
        const caption = item.getAttribute('data-caption');
        if (caption) {
          modalCaption.textContent = caption;
          modalCaption.style.display = 'block';
        }
      } else if (type === 'text') {
        const heading = item.getAttribute('data-heading');
        const paragraph = item.getAttribute('data-paragraph');
        if (heading) {
          modalHeading.textContent = heading;
          modalHeading.style.display = 'block';
        }
        if (paragraph) {
          modalDesc.textContent = paragraph;
          modalDesc.style.display = 'block';
        }
      }
      buildLinks(item);
      gameModal.classList.add('active');
    });
  });

  // Close Modal on X click
  modalClose.addEventListener('click', () => {
    gameModal.classList.remove('active');
    resetModal();
  });

  // Close Modal on clicking outside the content box
  gameModal.addEventListener('click', (e) => {
    if (e.target === gameModal) {
      gameModal.classList.remove('active');
      resetModal();
    }
  });
}

